import type {ArticleSection} from '../types/philosophy';

const section=(id:string,title:string,paragraphs:string[],relatedBranchIds?:string[],relatedPhilosopherIds?:string[],relatedWorkTitles?:string[]):ArticleSection=>({id,title,paragraphs,relatedBranchIds,relatedPhilosopherIds,relatedWorkTitles});

export const philosopherArticles:Record<string,ArticleSection[]>={
  plato:[
    section('overview','A philosophy written as an encounter',[
      'Plato is difficult to summarize because he does not write as a lecturer announcing settled conclusions. He writes dialogues: carefully staged encounters in which speakers pursue a question, discover that their first answers fail, and sometimes end without a final definition. The dramatic form is not decoration. It makes readers experience the difference between possessing a slogan and being able to give an account of what it means. Socrates is usually the central examiner, but the dialogues also let sophists, politicians, poets, mathematicians, and ambitious young Athenians expose the attractions and costs of rival ways of life.',
      'Across this changing body of work, Plato asks how judgment can become answerable to something more stable than reputation, appetite, or civic convention. Questions about courage or piety expand into questions about knowledge, reality, desire, education, and political rule. The theory of Forms is one response to that pressure: if judgments about justice or equality can be better or worse, perhaps they answer to intelligible standards that are not exhausted by any particular case. Yet Plato also subjects this proposal to severe criticism, especially in the Parmenides. Platonism therefore begins with both a metaphysical proposal and a discipline of self-questioning.'
    ],['platonism','epistemology','political-philosophy'],['socrates','aristotle'],['Apology','Republic','Parmenides']),
    section('historical-setting','Athens after confidence',[
      'Plato came of age during the Peloponnesian War, the defeat of Athens, the violent rule of the Thirty Tyrants, the restoration of democracy, and the execution of Socrates in 399 BCE. Those events give his political philosophy its urgency. The problem is not simply which constitution is best on paper. It is how a city forms citizens capable of distinguishing knowledge from persuasion, and how public speech can serve justice when ambition, fear, and faction reward something else. The dialogues repeatedly return to teachers, courts, assemblies, and households because philosophical failure is also educational and institutional failure.',
      'Socrates’ death becomes a test case for democratic judgment, but Plato does not replace democracy with easy confidence in experts. The Republic’s philosopher-rulers require an extraordinary education and remain vulnerable to corruption; the Statesman searches for genuine political knowledge while admitting how rare it is; the Laws turns toward institutions that can guide imperfect citizens. Plato’s political thought is best read as a continuing argument about expertise, formation, and accountability rather than a single constitutional blueprint.'
    ],['political-philosophy','ancient-greek'],['socrates'],['Apology','Republic','Statesman','Laws']),
    section('life-development','Life, Academy, and intellectual development',[
      'Reliable information about Plato’s life is limited, and later ancient biographies mix historical report with stories designed to express philosophical character. He belonged to an Athenian family with political connections and was close enough to the city’s conflicts to distrust both oligarchic violence and democratic complacency. His decisive intellectual relationship was with Socrates, whose trial and execution became an enduring problem rather than merely a personal loss. Plato preserves Socrates as an examiner of claims to wisdom, yet the literary Socrates changes across the dialogues and cannot simply be treated as a transcript of the historical man.',
      'Plato founded the Academy outside the walls of Athens, probably in the 380s BCE. It was not a modern university with a fixed curriculum or a church organized around a creed. It was a durable community of inquiry in which mathematics, astronomy, dialectic, ethics, and politics could be pursued together. Aristotle spent roughly two decades there before developing his own philosophy. The Academy matters because it gave philosophy an institutional form: questions could be inherited, criticized, and transformed across generations rather than depending on one teacher’s public performances.',
      'Scholars often group the dialogues into early, middle, and late periods. Early works tend to present Socratic examinations that end in perplexity; middle works develop more ambitious accounts of Forms, soul, education, and politics; late works often employ more technical divisions and reconsider earlier proposals. This chronology is useful but uncertain. Stylometric evidence supports some groupings, yet no surviving authorial outline tells us exactly when or why every dialogue was composed. The safest approach is to use developmental hypotheses as interpretive tools without forcing every disagreement into a simple story of Plato replacing one doctrine with another.',
      'The dialogue form makes intellectual development especially difficult to reconstruct. A character may defend a view because the dramatic situation calls for it, and an argument may fail in order to educate another speaker or the reader. Myths, analogies, speeches, and rigorous question-and-answer exchanges perform different tasks. Separating the historical Socrates, Plato’s own commitments, and the philosophical action of a particular dialogue therefore requires attention to genre and setting as well as argument.'
    ],['ancient-greek','platonism'],['socrates','aristotle'],['Apology','Republic','Laws']),
    section('knowledge-forms','Knowledge, Forms, and explanation',[
      'In the Meno, Socrates distinguishes true belief from knowledge by saying that true beliefs are valuable but liable to run away unless tied down by an account of the reason why. That image captures a recurring Platonic demand: knowing is not merely arriving at the correct answer. It involves understanding what makes the answer correct and how it belongs within a connected order of reasons. The dialogues test definitions because a definition should explain a range of cases without collapsing under counterexample.',
      'Forms enter as objects or structures suited to this explanatory demand. Equal sticks can appear equal in one respect and unequal in another, but the standard of equality does not fluctuate with them. Beautiful things change and compete, but judgments of beauty seem to reach beyond a list of attractive objects. Plato’s texts do not supply one simple theory of how Forms exist or how particulars participate in them. The Phaedo emphasizes explanatory priority, the Republic connects Forms to education and the Good, and the Parmenides exposes difficulties about separation, participation, and regress. The result is a research program, not a bumper sticker about a “world of Forms.”'
    ],['epistemology','metaphysics','platonism'],['parmenides','aristotle'],['Meno','Phaedo','Republic','Parmenides']),
    section('soul-education','Desire, soul, and education',[
      'Plato’s ethics begins from conflict within a person. In the Republic, reason, spirit, and appetite name distinguishable motivational tendencies: calculation about what is best, concern with honor and indignation, and bodily or acquisitive desire. Justice in the soul is not the elimination of desire but an order in which each part performs its role under intelligent direction. This psychological argument explains why political reform cannot consist only in changing laws. Institutions, stories, music, exercise, and habits educate what people love before abstract argument begins.',
      'The Symposium and Phaedrus complicate the picture by treating eros as a force that can be educated upward. Desire may fix on possession and prestige, but it can also become responsive to beauty, character, knowledge, and order. Philosophical education is therefore a conversion of attention and aspiration. The famous allegory of the cave is not a claim that sensible life is worthless; it depicts the painful reorientation required to recognize the conditions under which appearances become intelligible and then to return to shared political life.'
    ],['ethics','political-philosophy','platonism'],['socrates'],['Republic','Symposium','Phaedrus']),
    section('works-method','How the dialogues argue',[
      'The early definitional dialogues often end in aporia, a state of acknowledged perplexity. That ending is productive: a speaker who began with unexamined confidence now knows why the question is difficult. Middle dialogues such as the Phaedo, Symposium, and Republic construct larger positive arguments, but they remain dramatic and provisional. Later dialogues revise method, classify kinds, test Forms, and examine political rule with a different voice. Reading Plato well therefore requires attention to speaker, audience, setting, and what an argument is trying to accomplish within the conversation.',
      'A sensible reading route begins with the Apology, where philosophy appears as a public practice and a way of life. The Meno then shows a compact inquiry changing shape as definitions fail and the problem of learning emerges. Selected books of the Republic connect ethics, psychology, politics, and knowledge. Only after that foundation do the Phaedo and Parmenides reveal the strength and pressure points of the metaphysics. This order helps prevent a common mistake: extracting a doctrine from one memorable image and treating it as Plato’s entire philosophy.'
    ],['platonism'],['socrates'],['Apology','Meno','Republic','Phaedo','Parmenides']),
    section('major-works-early-middle','Major works: examination, knowledge, love, and death',[
      'The Apology presents Socrates defending his life of examination before an Athenian jury. Its philosophical problem is not only whether the charges are true, but what authority a person should obey when civic judgment conflicts with a reasoned sense of duty. The Crito continues that problem in prison. Socrates refuses an arranged escape and examines whether suffering injustice permits one to answer with injustice. Together the dialogues establish philosophy as accountable action rather than private speculation, while leaving difficult questions about obedience, law, and political responsibility.',
      'The Meno begins by asking whether virtue can be taught and quickly discovers that the speakers cannot define virtue. Meno’s paradox then asks how inquiry is possible: if one knows the object, inquiry is unnecessary; if one does not, how could one recognize it? Recollection and the mathematical questioning of an enslaved boy answer by showing learning as the elicitation and reorganization of latent understanding. The dialogue also distinguishes knowledge from true opinion, making explanation and stability central to epistemology.',
      'The Phaedo places arguments about soul, Forms, cause, and death within Socrates’ final hours. Its arguments for immortality remain contested, but the dialogue’s deepest achievement is to connect standards of explanation with a philosophical way of life. The Symposium approaches desire through a sequence of speeches whose limitations matter. Diotima’s account of ascent moves from attraction to a beautiful body toward appreciation of practices, knowledge, and beauty itself, yet the arrival of Alcibiades returns the reader to unresolved personal attachment and the singular force of Socrates.',
      'These dialogues should not be treated as detachable containers for doctrines. The setting of the Crito makes legal obligation urgent; the death scene of the Phaedo tests whether argument can shape fear; the competitive speeches of the Symposium expose how accounts of love reveal the speakers who give them. Plato uses dramatic form to show that a philosophical position is also a way of seeing, desiring, and responding.'
    ],['epistemology','ethics','platonism'],['socrates'],['Apology','Crito','Meno','Phaedo','Symposium']),
    section('major-works-system-late','Major works: Republic and the later investigations',[
      'The Republic begins with a question about justice and expands because each proposed definition implies a picture of human motivation and political order. Thrasymachus identifies justice with the advantage of the stronger; Glaucon presses Socrates to show that justice is worth choosing for itself. The constructed city allows the speakers to examine justice at a larger scale, but the analogy between city and soul never makes the politics merely decorative. Education, censorship, philosopher-rulers, communal arrangements among guardians, the so-called noble lie, and the exclusion or regulation of poetry remain serious and controversial proposals within the argument.',
      'The Theaetetus examines knowledge through definitions as perception, true judgment, and true judgment with an account. Its refusal to settle on a definition is philosophically important: it clarifies why knowledge cannot simply be identified with whatever appears to an individual or with accidental correctness. The Parmenides turns criticism inward by having the elder Parmenides interrogate a young Socrates about Forms. Problems of participation, separation, infinite regress, and the scope of Forms make the dialogue a warning against treating the theory as an easy solution.',
      'The Sophist develops a method of division to identify the elusive sophist and confronts the problem of false statement. To explain how falsehood is possible, the dialogue must show how not-being can mean difference rather than absolute nothingness. This changes the treatment of being and relation. The Timaeus offers a cosmological account in which a divine craftsman orders a preexisting receptacle according to intelligible models. Its status as a likely story matters: Plato presents a rationally ordered cosmos while marking the limits of certainty in natural explanation.',
      'The Laws, Plato’s longest dialogue, replaces the Republic’s philosopher-rulers with a more institutional project of legislation, education, mixed offices, and persuasive preambles to law. It is not simply a softened Republic; it asks how political order can guide citizens who will not become philosophers. Read beside the Statesman, it shows Plato continuing to wrestle with the gap between genuine expertise and the rules required when such expertise is unavailable or cannot safely govern without constraint.'
    ],['political-philosophy','epistemology','metaphysics'],['parmenides'],['Republic','Theaetetus','Parmenides','Sophist','Timaeus','Laws']),
    section('legacy-disputes','Inheritance and interpretive disputes',[
      'Aristotle’s philosophy develops through sustained disagreement with Plato over separate Forms, substance, explanation, ethics, and political science. Later Platonists systematize the dialogues in different ways; Plotinus places the intelligible Forms within Intellect and orders reality through the One, Intellect, and Soul. Augustine adapts Platonic inwardness and intelligibility within Christian theology. Islamic, Jewish, Byzantine, Renaissance, and modern philosophers continue to transform Platonic questions rather than merely repeat them.',
      'Interpretation remains divided over how unified Plato’s philosophy is, whether the dialogues reveal development across his career, and how literally to read their political proposals and myths. The Republic can look authoritarian when detached from its psychology and educational argument, while purely metaphorical readings can evade its political severity. The dialogues themselves encourage neither passive reverence nor quick dismissal. They ask readers to become responsible for the arguments they inherit.'
    ],['platonism','aristotelianism'],['aristotle','plotinus','augustine'],['Republic','Parmenides']),
    section('interpretive-disputes','What can responsibly be attributed to Plato?',[
      'The first dispute concerns Socrates. Some early dialogues may preserve recognizable features of the historical Socrates, while other works clearly use Socrates to develop arguments that cannot be independently attributed to him. Scholars have tried to identify a specifically Socratic philosophy and trace Plato’s later departures from it, but the evidence is literary and indirect. A responsible interpretation distinguishes historical reconstruction from analysis of the character’s role in a dialogue.',
      'A second dispute concerns unwritten teachings. Ancient reports, especially from Aristotle and later commentators, suggest that Plato discussed principles such as the One and the Indefinite Dyad orally. Some interpreters treat these reports as a key to a systematic philosophy intentionally withheld from writing. Others argue that elevating an oral doctrine above the dialogues misunderstands Plato’s deliberate use of literary form and overstates fragmentary testimony. The question changes whether the dialogues are viewed as incomplete public hints or as Plato’s primary philosophical achievement.',
      'The Forms generate another family of disputes. They can be read as separately existing metaphysical entities, as explanatory structures required by knowledge and predication, as ideals that guide dialectical inquiry, or as hypotheses whose limitations the dialogues expose. These interpretations need not be mutually exclusive, but each emphasizes different texts and faces different difficulties. The Republic’s politics is similarly contested. Authoritarian readings take its hierarchy, censorship, and guardian arrangements as serious evidence; more anti-authoritarian readings emphasize its critique of appetite, corruption, and false claims to knowledge. Neither approach should erase the proposals that make the other uncomfortable.',
      'Plato’s myths create a final interpretive challenge. The myth of Er, the chariot of the Phaedrus, the cosmology of the Timaeus, and other narratives are not ordinary demonstrations, yet they are not dispensable ornaments. They extend thought where strict argument reaches a limit, shape imagination and desire, and invite readers to test what kind of orientation a story produces. Interpretation must ask not only whether a myth is literally asserted, but what philosophical work it performs.'
    ],['platonism','political-philosophy','metaphysics'],['socrates','aristotle'],['Republic','Phaedrus','Timaeus']),
    section('reading-practice','How to read Plato',[
      'A beginner should expect conversations rather than a textbook. Start with the Apology to understand why philosophical examination is personally and politically demanding. Read the Crito beside it to see that Socratic integrity does not produce simple anti-authoritarianism. Move to the Meno for definition, inquiry, and knowledge, then to the Symposium or Phaedo for the relation between argument, desire, and dramatic setting. The Republic is best read in substantial sequences rather than through the cave alone, because its account of knowledge depends on psychology, education, and politics.',
      'While reading, keep track of who is speaking, what that person wants, and what has changed by the end. A refuted definition may still contain an insight; an apparently triumphant speech may reveal its speaker’s limitations. Notice transitions in method: examples give way to definitions, definitions to hypotheses, speeches to questioning, argument to myth. Ask whether an image concludes an argument or reorients the reader toward a problem that remains open.',
      'Do not expect every dialogue to fit one consistent doctrine without tension. Plato rewards rereading because later works alter the questions brought to earlier ones, and because dramatic details become philosophically visible only after the argument is understood. The most productive reader treats the dialogues neither as sacred authorities nor as puzzles to be solved once, but as designed occasions for practicing judgment. Plato’s enduring method is to make agreement less important than becoming able to explain why one agrees.'
    ],['platonism','epistemology'],['socrates'],['Apology','Crito','Meno','Republic'])
  ],
  kant:[
    section('overview','The critical turn',[
      'Kant’s critical philosophy asks a prior question before attempting traditional metaphysics: what must a finite rational subject contribute for experience, knowledge, and obligation to be possible at all? This does not make the world a private invention. It means that objects can become objects for us only through forms of sensible intuition and rules of conceptual synthesis. Kant calls this approach transcendental because it investigates conditions of possibility rather than merely cataloguing facts.',
      'The project spans three Critiques. The Critique of Pure Reason examines knowledge and the limits of theoretical reason. The Critique of Practical Reason and Groundwork investigate moral freedom and obligation. The Critique of Judgment asks how aesthetic judgment and the apparent purposiveness of organisms mediate between nature and freedom. Together they attempt to preserve scientific objectivity, moral responsibility, and rational hope without allowing speculative reason to claim knowledge it cannot justify.'
    ],['epistemology','metaphysics','ethics','german-idealism'],['hume'],['Critique of Pure Reason','Groundwork of the Metaphysics of Morals']),
    section('hume-problem','Hume, causality, and objective experience',[
      'Hume argues that experience presents one event followed by another but never displays a necessary connection binding them. Repeated sequences produce expectation through habit, not rational insight into causation. Kant accepts the force of this challenge. His answer is not to restore an older rationalism that reads necessary structures directly from reality. Instead, he argues that causality is among the categories through which the understanding unifies appearances into an objective temporal order.',
      'The distinction matters because a mere stream of sensations would not yet amount to experience of events in one shared world. To judge that the sun warmed the stone, rather than merely noticing warmth after sunlight, is to organize perceptions under a rule connecting states in time. Kant’s argument shifts epistemology from asking whether thought copies a fully organized world to asking how objective experience becomes possible. It also imposes a limit: categories legitimately organize possible experience, but they cannot simply be extended beyond experience to prove claims about the soul, cosmos, or God.'
    ],['epistemology','metaphysics','empiricism','rationalism'],['hume','descartes'],['Critique of Pure Reason','Prolegomena']),
    section('idealism','Appearances and things in themselves',[
      'Space and time, for Kant, are forms of sensible intuition: necessary structures under which objects can appear to human knowers. The categories, including substance and causality, are concepts required to synthesize those appearances into experience. Transcendental idealism therefore says that we know objects as they appear under these conditions, not as they might be independently of every possible relation to our mode of cognition.',
      'This position has generated one of the largest interpretive disputes in modern philosophy. A “two-world” reading treats appearances and things in themselves as different sets of entities; a “two-aspect” reading treats them as the same objects considered under different epistemic conditions. Both readings face pressure. Kant must explain how his view differs from ordinary empirical idealism while maintaining a meaningful limit on knowledge. His goal is to secure empirical realism: tables, planets, and other persons are genuinely knowable within experience, even though theoretical reason cannot step outside every condition of experience to compare appearances with reality in itself.'
    ],['epistemology','metaphysics','german-idealism'],['hume','hegel'],['Critique of Pure Reason']),
    section('ethics','Autonomy, duty, and dignity',[
      'Kant begins the Groundwork with the claim that a good will is good not because it reliably produces desired results but because of the principle on which it acts. Moral worth appears most clearly when an agent acts from duty rather than merely in accordance with duty. The categorical imperative tests whether the maxim of an action could be willed as a universal law and whether it treats rational beings always as ends, never merely as means.',
      'This is not a command to ignore consequences or mechanically follow rules. Kant is asking what it means for an action to be justified to any rational agent rather than licensed by one person’s advantage. Autonomy names rational self-legislation under such a principle; it contrasts with heteronomy, in which desire, authority, or promised reward supplies the law. The ideal of dignity follows because persons capable of practical reason cannot be assigned a price equivalent to other goods. Modern theories of rights and respect inherit this argument, while critics question its abstraction from emotion, dependency, history, and unequal social conditions.'
    ],['ethics','deontology','political-philosophy'],['rousseau','rawls'],['Groundwork of the Metaphysics of Morals','Critique of Practical Reason']),
    section('judgment-history','Judgment, enlightenment, and history',[
      'The third Critique investigates judgments that do not fit neatly into deterministic natural science or moral law. A judgment of beauty claims a kind of shareable validity without applying a determinate concept. Reflection on organisms encounters parts that seem intelligible through their relation to a whole, even though Kant refuses to turn purposiveness into ordinary causal knowledge. These analyses ask how human judgment navigates a world that must be understood as nature while practical reason requires us to act as free.',
      'Kant’s public essays connect enlightenment to the courage to use one’s own understanding and defend a public use of reason. Yet the universal aspirations of the critical philosophy coexist with hierarchical writings about race, anthropology, sex, and civilization. Those texts are not incidental to assessing the scope and limits of Kantian universalism. Contemporary interpreters dispute whether the resources of autonomy and dignity can criticize these exclusions from within Kant’s framework or whether the framework itself carries deeper historical distortions.'
    ],['aesthetics','political-philosophy','german-idealism'],['rousseau','hegel'],['Critique of Judgment','What Is Enlightenment?']),
    section('legacy','After Kant',[
      'Fichte, Schelling, and Hegel argue that Kant leaves unresolved divisions between appearance and thing in itself, nature and freedom, or theoretical and practical reason. German Idealism tries to reconstruct these relations historically and systematically. Schopenhauer transforms Kant through a metaphysics of will; phenomenology inherits transcendental questions about the structures of experience; analytic philosophy repeatedly returns to conceptual conditions, normativity, and the limits of metaphysics.',
      'Kant also remains central to ethics and political philosophy. Rawls adapts Kantian ideas of fairness and public justification; Habermas develops a procedural account of communicative reason; deontologists debate duties, rights, and exceptions. Reading Kant requires holding together two facts: the critical project permanently changed how philosophy understands its own limits, and its claims to universality must be tested against the exclusions and assumptions within Kant’s actual writings.'
    ],['german-idealism','ethics','epistemology'],['hegel','schopenhauer','rawls'],['Critique of Pure Reason','Groundwork of the Metaphysics of Morals'])
  ],
  nietzsche:[
    section('overview','Philosophy as diagnosis',[
      'Nietzsche treats philosophy less as the construction of a neutral system than as the diagnosis of values, habits, and forms of life. He asks not only whether a belief is true, but what kind of need it expresses, what practices sustain it, and what effects it has on those who live by it. This does not make truth irrelevant. It makes the will to truth itself available for examination: why do we value truth unconditionally, and what happens when inherited guarantees of its value collapse?',
      'His writing changes form because the task changes. Aphorisms allow competing perspectives to remain active; genealogical essays reconstruct layered histories; Thus Spoke Zarathustra stages teaching, failure, and self-overcoming as philosophical drama. Nietzsche’s provocations are designed to interrupt moral reflexes, but they are not permission to quote an isolated sentence as a doctrine. The reader must follow the target, context, and psychological function of each claim.'
    ],['continental-philosophy','ethics','existentialism'],['schopenhauer'],['The Gay Science','Beyond Good and Evil']),
    section('formation','Philology, tragedy, and the problem of culture',[
      'Nietzsche was trained as a classical philologist and became a professor at Basel while still in his twenties. The Birth of Tragedy interprets Greek tragedy through the tension between Apollonian form and Dionysian excess. Although he later criticized the book’s style and Wagnerian hopes, its central question persists: can a culture affirm suffering and contingency without fleeing into moralized consolation?',
      'His break with Wagner and Schopenhauer redirects that question. Schopenhauer had treated striving as the source of suffering and aesthetic contemplation as temporary release. Nietzsche comes to suspect that pessimistic renunciation may itself express a judgment against life. The middle-period works adopt a freer, experimental style and use historical psychology to examine morality, religion, art, and knowledge. Philosophy becomes an effort to identify which evaluations strengthen capacities and which convert vulnerability into hostility toward existence.'
    ],['aesthetics','continental-philosophy'],['schopenhauer'],['The Birth of Tragedy','Human, All Too Human']),
    section('genealogy','Genealogy and moral psychology',[
      'Genealogy does not simply reveal that values have histories. It asks how a value’s meaning changes as different groups and practices appropriate it. In the first essay of On the Genealogy of Morality, Nietzsche contrasts a noble mode of valuation that begins by affirming itself with a reactive mode that first names an enemy evil and defines itself as good by opposition. The contrast is a psychological and historical hypothesis, not a timeless sorting of people into social castes.',
      'The later essays examine guilt, punishment, bad conscience, and the ascetic ideal. Practices of punishment do not possess one stable meaning; guilt develops through relations of debt and internalized aggression; ascetic ideals give suffering an interpretation and thereby make it bearable, even while intensifying hostility toward desire and embodiment. Nietzsche’s explanation is deliberately double-edged. An ideal can discipline and deepen human capacities while also turning those capacities against life.'
    ],['ethics','continental-philosophy'],['foucault'],['On the Genealogy of Morality']),
    section('perspective-truth','Perspective, truth, and interpretation',[
      'Perspectivism begins from the claim that knowing is an activity of embodied, interested interpreters. Attention selects, concepts simplify, and inquiry is guided by questions and values. Nietzsche rejects the fantasy of a view from nowhere, but he does not conclude that every interpretation is equal. Some perspectives incorporate more evidence, withstand stronger counterpressure, disclose their own commitments, or increase the capacity to understand.',
      'This position creates a difficult problem: can Nietzsche criticize dogmatism without turning perspectivism into another dogma? His strongest passages present perspective as an argument for disciplined plurality. Objectivity is not the absence of every standpoint but the ability to employ and contest multiple standpoints rather than remaining imprisoned in one. Later thinkers, especially Foucault, extend this insight by studying how institutions and practices shape what can count as knowledge.'
    ],['epistemology','continental-philosophy'],['foucault'],['Beyond Good and Evil','On the Genealogy of Morality']),
    section('nihilism','Nihilism, recurrence, and affirmation',[
      'The “death of God” names a cultural event in which inherited moral and metaphysical authority loses credibility while its values continue to organize life. Nietzsche’s concern is not simply whether individuals believe in God. It is whether European commitments to truthfulness undermine the foundations that once guaranteed truth and morality, leaving people unable to explain why inherited values should bind them. Nihilism is the resulting crisis of valuation.',
      'Nietzsche’s responses are experiments rather than a replacement catechism. Self-overcoming asks whether a form of life can transform its own habits and standards. Eternal recurrence functions as a severe test: could one affirm this life, including its suffering and contingency, without demanding another world to redeem it? The language of will to power describes interpretation, organization, contest, and expansion of capacity, but it should not be reduced to a political slogan about dominating others.'
    ],['existentialism','continental-philosophy'],['camus'],['The Gay Science','Thus Spoke Zarathustra']),
    section('appropriation','Legacy and dangerous appropriations',[
      'Nietzsche influenced existentialism, psychoanalysis, modernist literature, genealogy, deconstruction, and moral psychology. Foucault adopts genealogy while shifting its focus toward institutions and subject formation. Beauvoir and other existentialists take seriously the problem of creating values under conditions without guaranteed meaning. Analytic philosophers increasingly engage Nietzsche’s accounts of agency, reasons, and moral psychology.',
      'His legacy is inseparable from political misuse. Nietzsche’s contempt for nationalism and antisemitism did not prevent selective editing and appropriation by fascists, aided by his sister’s control of the archive. His own anti-egalitarian rhetoric and admiration for hierarchy remain genuine problems that cannot be explained away by those distortions. Responsible reading distinguishes fabricated systematization from Nietzsche’s published work while still confronting the exclusions and dangers present there.'
    ],['continental-philosophy','existentialism'],['foucault','beauvoir'],['On the Genealogy of Morality','Beyond Good and Evil'])
  ],
  wittgenstein:[
    section('overview','Two revolutions in philosophical method',[
      'Wittgenstein changed analytic philosophy twice. The Tractatus Logico-Philosophicus tries to identify the logical conditions under which propositions can represent facts. Philosophical confusion arises when language attempts to state what can only be shown in the meaningful use of signs. The later Philosophical Investigations rejects the expectation that language must possess one underlying essence and studies the many activities in which words acquire sense.',
      'Despite the contrast, both periods treat philosophy as clarification rather than the discovery of additional facts alongside scientific facts. Wittgenstein asks what gives a question sense, what rules govern the expressions involved, and why a picture of language makes a problem seem unavoidable. This therapeutic ambition does not make the problems trivial. It requires unusually patient attention to examples, practices, temptations, and the point at which an explanation has actually done its work.'
    ],['analytic-philosophy','philosophy-of-language','logic'],['frege','russell'],['Tractatus Logico-Philosophicus','Philosophical Investigations']),
    section('early','Logical form and the limits of saying',[
      'The early Wittgenstein inherits from Frege and Russell the project of explaining how language can represent reality. In the Tractatus, an elementary proposition pictures a possible state of affairs because its elements are arranged in a way that shares logical form with what it represents. Complex propositions are truth-functions of elementary propositions. Logic is not a body of facts; it displays the scaffolding that meaningful propositions already presuppose.',
      'This account sharply limits meaningful saying. Ethics, aesthetics, the meaning of life, and logical form itself cannot be represented as ordinary facts. The book’s own propositions therefore occupy a deliberately unstable position: the reader is asked to use them as a ladder and then recognize their nonsensical status. Logical positivists took the work as support for excluding metaphysics, but the Tractatus also insists that what matters most is not thereby dismissed as unimportant.'
    ],['logic','analytic-philosophy'],['frege','russell'],['Tractatus Logico-Philosophicus']),
    section('later','Language-games and meaning as use',[
      'The Investigations opens by criticizing a picture in which every word names an object and every sentence combines names. Wittgenstein replaces that uniform picture with language-games: requesting, reporting, joking, calculating, thanking, commanding, and countless other activities. To understand an expression is to grasp how it functions within such a practice, not necessarily to associate it with a private object or a complete definition.',
      '“Meaning is use” is therefore a methodological redirection, not a slogan that answers every semantic question. Wittgenstein asks readers to look at differences that philosophical theory smooths over. The word “game” has no single feature shared by every game; overlapping similarities can sustain a concept. A rule does not contain all its applications as an interpretation waiting to be decoded; rule-following is anchored in learned practices where correction and agreement have a role.'
    ],['philosophy-of-language','analytic-philosophy'],[],['Philosophical Investigations']),
    section('mind','Private language, sensation, and mind',[
      'The private-language discussion targets the idea of a language whose signs refer to sensations identifiable only through an individual’s private act of attention. If nothing distinguishes using the sign correctly from merely seeming to use it correctly, the sign cannot function as a rule-governed expression. Wittgenstein is not denying pain or claiming that others know one’s pain exactly as the sufferer does. He is challenging a picture in which meaningful psychological language is built by attaching labels to inaccessible inner objects.',
      'This changes philosophy of mind. Expressions of pain belong to patterns of behavior, circumstance, response, and learning; they are not uncertain reports inferred from hidden inner entities. First-person and third-person psychological statements have different roles. The approach resists both crude behaviorism and a Cartesian theater of private objects. It asks how concepts of thought, intention, understanding, and sensation operate in human life.'
    ],['philosophy-of-mind','philosophy-of-language'],['descartes'],['Philosophical Investigations']),
    section('certainty','Doubt, hinges, and forms of life',[
      'In On Certainty, Wittgenstein responds to skeptical problems by examining the role of doubt. Doubting makes sense only against a background of things not currently doubted: that words have stable uses, that inquiry can continue, that records and perceptions generally connect to a shared world. Some commitments function as hinges around which testing and justification turn. They are not ordinary hypotheses supported by stronger evidence, but neither are they arbitrary private choices.',
      'The notion of a form of life names the broader patterns of action, response, and agreement within which language-games make sense. It does not settle every disagreement by appeal to convention. It shows why justification must eventually reach practices rather than continue as an infinite chain of propositions. This insight influences epistemology, anthropology, social theory, and debates about whether reasons can be separated from the lives in which they count as reasons.'
    ],['epistemology','analytic-philosophy'],[],['On Certainty','Philosophical Investigations']),
    section('legacy','Continuity, therapy, and legacy',[
      'Interpreters disagree about whether the later Wittgenstein repudiates the Tractatus or carries forward its ethical and therapeutic aim by different means. Both works oppose the idea that philosophy should compete with science by constructing theories of hidden objects. Yet the early work seeks a definitive logical boundary, while the later work distrusts the craving for a single purified form. That tension makes Wittgenstein’s development philosophically productive rather than merely biographical.',
      'His influence extends through ordinary-language philosophy, philosophy of mind, rule-following, mathematics, action, religion, and social practice. Some readers treat his method as dissolving philosophical problems; others argue that his descriptions support substantive claims about language and normativity. The best way to begin is not to memorize “meaning is use,” but to follow several examples closely enough to notice the picture of language that made a philosophical difficulty appear compulsory.'
    ],['analytic-philosophy','philosophy-of-language'],['russell','anscombe'],['Tractatus Logico-Philosophicus','Philosophical Investigations','On Certainty'])
  ]
};

export const branchArticles:Record<string,ArticleSection[]>={
  platonism:[
    section('overview','A tradition of intelligible order',[
      'Platonism is not one doctrine transmitted unchanged from Plato. It is a family of arguments organized around the conviction that explanation, knowledge, and value cannot be exhausted by changing sensible particulars. Platonists ask what makes many things count as equal, beautiful, or just; how the mind can grasp stable structures; and how philosophical education can reorient desire toward what is genuinely good.',
      'The tradition begins in dialogues that resist systematization. Later Platonists make the inheritance more explicit, identifying hierarchies of reality, accounts of participation, and practices of intellectual ascent. This creates an enduring tension: Platonism seeks comprehensive intelligibility, yet its founding texts repeatedly dramatize inquiry, failure, and revision.'
    ],['metaphysics','epistemology'],['plato','plotinus'],['Republic','Parmenides']),
    section('academy-origins','Dialogues, Academy, and the beginning of a tradition',[
      'Platonism begins as interpretation because Plato’s dialogues do not present a creed in the author’s voice. They offer arguments in dramatic situations, use myths alongside demonstrations, and sometimes criticize proposals developed elsewhere in the corpus. The first Platonists therefore inherited not only claims about Forms, soul, or the good, but also a problem of reading: which positions organize the dialogues, which are provisional, and how should philosophical teaching relate to written texts that deliberately refuse the shape of a manual?',
      'The Academy gave this interpretive problem an institutional life. Plato’s successors did not merely preserve his words. Speusippus, who led the Academy after Plato, apparently rejected Forms of sensible things and developed a more complex hierarchy of principles. Xenocrates gave stronger systematic form to divisions among intelligible, celestial, and sensible reality. Their differences show that early Platonism was already an argument over how to develop Plato rather than an exercise in repetition. Mathematics, astronomy, ethics, and dialectic belonged to the same intellectual environment because each could reveal forms of order unavailable to untrained perception.',
      'Aristotle is both Platonism’s most famous critic and one of its formative heirs. He rejects separately existing Forms as inadequate explanations of sensible substances, yet retains the demand that knowledge grasp causes, structures, and intelligible form. His reports about Plato and the Academy are indispensable but philosophically interested; they often translate dialogical arguments into the terms of Aristotle’s own disputes. The boundary between Platonism and Aristotelianism is therefore porous from the beginning. Later Platonists repeatedly borrow Aristotelian logic and psychology while criticizing his account of first principles.',
      'The Academy itself changed direction over time. Arcesilaus and Carneades developed a skeptical Academy that used Socratic questioning and Plato’s anti-dogmatic moments to resist claims of certainty. This phase demonstrates that ancient Platonism could understand fidelity to Plato as disciplined suspension rather than metaphysical system-building. When later Platonists returned to stronger doctrines about intelligible reality and divine order, they did so against a history that had already made disagreement part of the tradition.'
    ],['platonism','aristotelianism','skepticism'],['plato','aristotle'],['Republic','Parmenides']),
    section('forms-participation','Forms, participation, and the Good',[
      'Forms answer an explanatory problem. Particular beautiful things change, conflict, and admit degrees, while judgments about beauty seem to answer to a standard not identical with any one example. Platonists differ over whether Forms are separate entities, divine thoughts, structures within intellect, or objective patterns described by another vocabulary. Participation names the equally difficult question of how particulars depend on or instantiate those standards.',
      'The Form of the Good in the Republic connects intelligibility and value. Just as light makes vision possible, the Good is presented as making knowledge and being intelligible. Later Platonists intensify this ordering role, especially Plotinus, for whom the One exceeds determinate being and intellect. The tradition’s strength is its refusal to separate facts from the conditions that make truth and value possible; its recurring difficulty is explaining the relation between higher principles and ordinary things.'
    ],['metaphysics','epistemology'],['plato','plotinus'],['Republic','Enneads']),
    section('universals-mathematics','Universals, mathematics, and explanation',[
      'The problem of universals gives Platonism one of its most durable forms. Many distinct objects can be triangular, courageous, or red. A realist asks whether this shared feature depends on something objective rather than only on a name applied by speakers. Strong Platonist answers treat universals as independent of particular instances and of individual minds. More moderate answers treat them as objective structures or repeatable features without placing them in a separate realm. Nominalists reject such entities and explain generality through language, resemblance, concepts, or practices.',
      'Mathematics makes the realist pressure especially vivid. Mathematical reasoning concerns exact triangles, infinite series, numbers, sets, and proofs that do not appear to depend on the imperfections of physical examples. Mathematical Platonists argue that such objects or truths are discovered rather than invented and that their necessity cannot be reduced to empirical regularity. Opponents ask how embodied knowers could gain knowledge of abstract, causally inert objects. This epistemological challenge is central: Platonism must explain not only what abstract objects are, but how reasoning can be reliably answerable to them.',
      'Participation is the ancient name for a related explanatory problem. If particular acts are just because they participate in justice, what kind of relation is participation? If a Form is wholly present in many particulars, how does it remain one? If Forms resemble their instances, does that require a further Form explaining the resemblance? Plato’s Parmenides stages these objections rather than concealing them. Later Platonists respond by locating Forms within intellect, ordering levels of dependence, or distinguishing causal presence from physical division.',
      'Contemporary metaphysics often uses different vocabulary, discussing instantiation, properties, propositions, grounding, or structural realism. The Platonist impulse remains recognizable whenever explanation appeals to objective patterns that are not identical with the concrete cases they organize. The dispute matters because it changes what knowledge is about. If general truths answer only to language or conceptual schemes, inquiry has one kind of authority; if they answer to mind-independent structure, it has another.'
    ],['metaphysics','epistemology','logic'],['plato'],['Parmenides','Republic']),
    section('history','Academy, late antiquity, and religious transformations',[
      'The early Academy pursued mathematics, dialectic, ethics, and politics, but it did not preserve a single orthodoxy. At different moments Academic philosophers emphasized metaphysical construction or skeptical resistance to dogmatic certainty. Middle Platonists later developed more systematic accounts of Forms, soul, and divine intellect, often incorporating Aristotelian and Stoic material.',
      'Plotinus reorganized this inheritance around the One, Intellect, and Soul, establishing what modern historians call Neoplatonism. Christian, Jewish, and Islamic thinkers adapted Platonic accounts of participation, immaterial truth, and ascent while rejecting or transforming claims incompatible with creation, revelation, or divine personality. Augustine’s inward turn and account of illumination are major examples of this productive transformation.'
    ],['neoplatonism','philosophy-of-religion'],['plotinus','augustine'],['Enneads','Confessions']),
    section('middle-neoplatonism','Middle Platonism, Plotinus, and systematic ascent',[
      'From roughly the first century BCE through the second century CE, thinkers now called Middle Platonists sought to coordinate Plato’s dialogues into a more systematic philosophy. They interpreted the Timaeus, Republic, and other works through debates with Aristotle, Stoicism, and contemporary religious thought. Many identified Forms with thoughts in a divine intellect, developed hierarchies of soul and matter, and treated Plato as an authoritative but interpretable source. The period prepared concepts later transformed by Plotinus, even though it did not speak with one voice.',
      'Plotinus gives Platonism a new architecture. The One is not one being among others but the source beyond determinate being. Intellect contains the Forms as a living intelligible order, and Soul mediates intelligible structure to the sensible cosmos. Reality proceeds from higher principles without those principles being depleted, and philosophical life becomes a movement of return toward the source. This language of procession and return systematizes Platonic themes of dependence, contemplation, and ascent while going well beyond anything stated straightforwardly in a single dialogue.',
      'Neoplatonism is therefore not merely Plato repeated with mystical language. Plotinus argues against some readings of the Timaeus, rejects the idea that the sensible cosmos is evil, and develops a sophisticated account of how multiplicity can depend on unity. Porphyry organizes and transmits Plotinus’s writings; Iamblichus gives greater importance to ritual and theurgy; Proclus elaborates a densely structured metaphysics of causes, participation, and divine orders. Their disagreements concern how far intellectual contemplation can carry the soul and how philosophical reasoning relates to religious practice.',
      'The tradition’s account of ascent can sound like hostility toward embodied life, but its major thinkers often describe the sensible cosmos as an image whose order derives from intelligible causes. The problem is not that bodies simply fail to exist. It is that attention can mistake derivative and changing goods for self-sufficient reality. That distinction later allowed religious thinkers to adapt Neoplatonic hierarchy while reinterpreting creation, embodiment, and divine action.'
    ],['neoplatonism','metaphysics'],['plotinus'],['Timaeus','Enneads']),
    section('religious-reception','Christian, Jewish, and Islamic transformations',[
      'Christian Platonism adopts concepts of immaterial truth, participation, divine exemplars, and inward ascent while transforming the metaphysical framework around creation and a personal God. Augustine encountered books of the Platonists that helped him conceive God and soul as immaterial, overcoming the materialist assumptions that had blocked his earlier thinking. Yet he argues that Platonist ascent does not by itself supply the humility, grace, and historical mediation central to Christianity. In his work, illumination and participation become ways of explaining how finite minds and created goods depend on divine truth.',
      'Later Christian Platonists, including Pseudo-Dionysius, use hierarchical procession and return to describe creation, divine names, and contemplative ascent. These adaptations create enduring tensions. If all things proceed from a highest source, how should creation from nothing be distinguished from necessary emanation? If evil is privation rather than a positive substance, how should moral responsibility and severe suffering be explained? If the highest principle exceeds language, how can revealed claims be affirmed rather than dissolved into negative theology?',
      'Jewish philosophers engage Platonic and Neoplatonic materials through multiple routes, often in conversation with Aristotelianism and Arabic philosophy. Themes of divine simplicity, emanation, intellect, and the soul’s perfection are adapted under commitments to creation, law, and revelation. Islamic philosophers likewise inherit a late antique philosophical curriculum in which Plato, Aristotle, and Neoplatonic texts were already intertwined. Al-Farabi’s political philosophy, Avicenna’s metaphysics of necessity and intellect, and later illuminationist traditions develop questions that cannot be classified as simply Platonic or Aristotelian.',
      'These receptions matter because they reveal Platonism’s flexibility and its limits. Participation, intelligible order, and ascent offered powerful tools for explaining how a transcendent source could be related to a structured world. At the same time, revealed traditions resisted the impersonality, necessity, or cyclical cosmology associated with some Platonist systems. The resulting syntheses are not secondary footnotes to ancient philosophy; they are major philosophical reconstructions that changed what Platonism could mean.'
    ],['philosophy-of-religion','islamic-philosophy','medieval-scholasticism'],['augustine','avicenna','al-farabi'],['Confessions','Enneads']),
    section('education-politics','Education, desire, and political order',[
      'Platonism treats education as formation of desire and judgment, not mere transfer of information. The cave allegory depicts the pain of reorientation: familiar appearances and social rewards can make ignorance feel like competence. Dialectic tests assumptions, while mathematics trains attention toward stable relations. The learner must become able to recognize why an answer is better, not simply repeat it.',
      'This educational ideal has political consequences. If rule requires knowledge of justice and the good, political authority cannot be justified by power or popularity alone. Yet the proposal creates dangers of paternalism and unaccountable expertise. Platonist political thought therefore remains important wherever institutions must relate truth, professional knowledge, democratic participation, and civic formation.'
    ],['political-philosophy','epistemology'],['plato'],['Republic','Laws']),
    section('debates','Internal debates and rivals',[
      'Aristotle’s criticism of separate Forms is the most influential internal challenge. If Forms are separated from sensible things, he argues, they may duplicate rather than explain those things. Platonists answer by refining participation or locating Forms within intellect. Skeptical Platonists question whether human beings can claim the kind of knowledge dogmatic systems promise. Later debates concern whether the highest principle is personal, intellectual, or beyond being.',
      'Modern mathematical and moral realism revive recognizably Platonic questions without necessarily accepting ancient cosmology. Critics argue that abstract entities are causally inert or explanatorily expensive; defenders reply that mathematics, properties, and objective value are difficult to understand without structures that exceed particular instances. Platonism persists because the problem it addresses persists: how can thought answer to standards that are neither arbitrary inventions nor merely one more changing object?'
    ],['aristotelianism','skepticism','metaphysics'],['aristotle'],['Metaphysics','Parmenides']),
    section('medieval-modern','From medieval universals to contemporary realism',[
      'Medieval disputes over universals reorganized a recognizably Platonist problem inside scholastic vocabularies. Realists defended the objectivity of common natures or forms, while nominalists denied that universals exist as shared entities outside signs or concepts. The positions were rarely simple repetitions of Plato. Thinkers distinguished universals before things in divine intellect, in things as their common nature, and after things as concepts abstracted by minds. These distinctions made the ancient problem more precise while binding it to theology, logic, and theories of cognition.',
      'Renaissance Platonism renewed direct study of Plato and late ancient Platonists. Marsilio Ficino translated and interpreted Plato and Plotinus, presenting Platonic philosophy as compatible with Christian truth and emphasizing the soul’s place within an ordered cosmos. Platonist themes also supported confidence in mathematical structure and the intelligibility of nature, although the emergence of modern science cannot be credited to a single philosophical school. The Cambridge Platonists later opposed both reductive materialism and rigid religious dogmatism by appealing to reason, objective morality, and an intelligible spiritual order.',
      'Modern philosophy often rejects central Platonist commitments while preserving its questions. Empiricism challenges knowledge not grounded in experience; materialism resists irreducible immaterial structures; historicism emphasizes the formation of concepts through changing practices; naturalism asks that explanations remain continuous with successful science. Kant denies that theoretical reason can know traditional supersensible objects, yet his account of necessary conditions of experience and objective moral law retains a concern with standards not derived from individual preference.',
      'Contemporary Platonism is most visible in debates over abstract objects. Mathematical Platonists defend mind-independent numbers, sets, or structures. Realists about properties and propositions argue that predication and truth require objective entities or relations. Moral realists defend values or reasons not reducible to attitudes. These views differ sharply and may share little with ancient theories of soul or political education. Calling them Platonist identifies a family resemblance: the claim that thought and judgment answer to intelligible realities that do not depend for their existence on particular material instances or acts of thinking.'
    ],['metaphysics','epistemology'],['kant'],['Parmenides','Critique of Pure Reason']),
    section('internal-questions','Recurring internal questions',[
      'Platonism’s central internal question is how intelligible structure relates to sensible reality. If Forms are wholly separate, they risk becoming irrelevant duplicates. If they are merely concepts within human minds, they may no longer explain objective agreement or error. Locating Forms in divine or cosmic intellect solves some problems while introducing theological commitments. Structural interpretations avoid picturing Forms as objects in another place, but they must still explain what makes a structure real and how particulars instantiate it.',
      'The Good creates a similar range of interpretations. In the Republic it is the source of intelligibility and being, yet it is introduced through analogy rather than a direct definition. It can be read metaphysically as a highest principle, ethically as the standard of right order, educationally as the aim that organizes inquiry, or theologically as anticipating a divine source. Later Platonists often combine these roles. Critics ask whether doing so illegitimately turns value into a feature of cosmic hierarchy and political authority.',
      'Platonism also faces a political and educational tension. Its insistence that judgment requires formation can expose manipulation, ignorance, and false expertise. The same insistence can justify elitism if a group claims privileged access to truth without accountability. The Republic dramatizes this danger through the extraordinary demands and vulnerabilities of philosopher-rulers. Modern readers must ask whether Platonist education cultivates shared capacities for reason or reserves authority for those who declare themselves already enlightened.',
      'Finally, Platonists disagree over the sensible world. Some rhetoric of ascent encourages the impression that bodies, change, and ordinary life are obstacles to be escaped. Other texts describe the cosmos as ordered, beautiful, and worthy of understanding precisely because it images intelligible structure. The strongest forms of Platonism do not deny appearances; they ask what makes appearances intelligible and how attention can learn to distinguish a dependent good from an ultimate source.'
    ],['platonism','political-philosophy','metaphysics'],['plato','plotinus'],['Republic','Timaeus','Enneads']),
    section('reading','How to read the tradition',[
      'Begin with Plato’s Apology and Meno to encounter philosophical examination before approaching a system. Read selected books of the Republic for the connections among justice, soul, education, and knowledge. The Phaedo offers a forceful account of Forms and explanation; the Parmenides then prevents easy confidence by testing that account’s difficulties.',
      'Plotinus should be read as a major philosopher transforming Plato, not as a glossary of Platonic doctrine. Augustine shows how Platonist structures change inside Christian thought. A productive reading path compares these appropriations and asks what each gains or loses when it makes the dialogues more systematic.'
    ],['platonism','neoplatonism'],['plato','plotinus','augustine'],['Apology','Meno','Republic','Parmenides','Enneads']),
    section('reading-path','A staged reading path through Platonism',[
      'Begin with Plato before beginning with a definition of Platonism. The Apology presents philosophical examination as a life and public practice; the Meno introduces definition, recollection, and the difference between knowledge and true opinion. Read substantial portions of the Republic, especially Books I, IV, VI, VII, and X, to see how Forms and the Good belong to an argument about psychology, education, politics, and poetry. The Phaedo clarifies the explanatory appeal of Forms, while the Parmenides supplies the necessary internal criticism.',
      'Next read Plotinus selectively, using an introduction that explains the organization of the Enneads. Treat the One, Intellect, and Soul as arguments about dependence and unity rather than as a list of supernatural regions. Augustine’s Confessions, especially the books on conversion, memory, creation, and time, shows a major religious transformation of Platonist inwardness. Proclus offers a more systematic and difficult late ancient development for readers who want to understand participation and hierarchy in their most elaborate form.',
      'For modern questions, choose the Platonism that matches the problem. A reader interested in universals should compare realist and nominalist accounts of properties. A reader interested in mathematics should study the epistemological problem of knowledge of abstract objects. A reader interested in ethics should compare moral realism with constructivist and naturalist alternatives. Throughout, avoid treating historical influence as identity: a contemporary mathematical Platonist need not accept Plato’s politics, and a Christian Platonist does not simply reproduce Plotinus. The tradition is best understood by following how one explanatory pressure generates different systems.'
    ],['platonism','neoplatonism','metaphysics'],['plato','plotinus','augustine'],['Apology','Republic','Parmenides','Enneads','Confessions'])
  ],
  epistemology:[
    section('overview','What separates knowledge from getting it right?',[
      'Epistemology studies knowledge, justified belief, evidence, rational confidence, and the possibility of error. Its central problem is not simply how to accumulate true statements. A lucky guess can be true without being knowledge, while a responsibly formed belief can turn out false. Epistemology asks what relation a knower must have to truth, reasons, methods, and other people for a belief to count as knowledge.',
      'The field changes when its picture of the knower changes. Classical and early modern discussions often begin with an individual confronting skeptical doubt. Contemporary epistemology also studies testimony, institutions, expertise, ignorance, and power. The knower is not only a private mind but a participant in social practices that distribute information and credibility unevenly.'
    ],['epistemology','skepticism'],['plato','descartes'],['Theaetetus','Meditations on First Philosophy']),
    section('classical','From Plato to skepticism',[
      'Plato’s Theaetetus tests definitions of knowledge as perception, true judgment, and true judgment with an account. None is accepted without difficulty. The dialogue establishes a durable distinction between believing truly and understanding why. Aristotle develops a demanding model of scientific knowledge in which demonstration explains a conclusion through appropriate causes and principles.',
      'Ancient skeptics challenge whether claims can survive disagreement, changing appearances, and the demand for justification. Pyrrhonian skepticism does not simply assert that knowledge is impossible; it suspends judgment where opposing considerations remain balanced. This makes skepticism both an intellectual challenge and a practice aimed at changing one’s relation to certainty.'
    ],['skepticism','ancient-greek'],['plato','aristotle','pyrrho'],['Theaetetus','Posterior Analytics']),
    section('modern','Reason, experience, and the external world',[
      'Descartes uses methodic doubt to search for beliefs immune to deception, dreams, and unreliable inheritance. The cogito establishes certainty in the act of thinking, but reconstructing knowledge of God, body, and external world proves more difficult. Rationalists emphasize structures available to reason; empiricists investigate how experience supplies ideas and warrants belief.',
      'Hume presses empiricism toward a crisis. Experience shows repeated sequences but not necessary causal connection, and no non-circular argument proves that the future will resemble the past. Kant answers by arguing that causality and other categories are conditions under which appearances can form objective experience. This does not defeat every skeptical challenge, but it changes the question from whether the mind copies order to how object-experience becomes possible.'
    ],['rationalism','empiricism','metaphysics'],['descartes','hume','kant'],['Meditations on First Philosophy','Enquiry Concerning Human Understanding','Critique of Pure Reason']),
    section('analysis','Justification, Gettier, and epistemic luck',[
      'Twentieth-century analytic epistemology often analyzed knowledge as justified true belief. Gettier’s short counterexamples show that a person can possess a justified true belief whose truth depends on luck. The ensuing debate asks whether knowledge requires reliability, safety, sensitivity, proper function, intellectual virtue, or some relation not captured by adding another condition to the traditional formula.',
      'These proposals divide over what must be accessible to the knower. Internalists require that justification depend on reasons available from the subject’s perspective. Externalists allow reliable processes or appropriate relations to truth to confer knowledge even when the subject cannot fully explain them. The dispute matters for children, animals, perception, expertise, and ordinary knowledge, not only artificial examples.'
    ],['analytic-philosophy'],[],['Is Justified True Belief Knowledge?']),
    section('social','Testimony, expertise, and epistemic injustice',[
      'Most of what any person knows depends on testimony. Historical facts, scientific results, geography, and current events arrive through other people and institutions. Social epistemology asks when trust is warranted, how communities divide cognitive labor, and what makes expertise reliable. The aim is not blind deference but an account of responsible dependence under conditions where no individual can verify everything.',
      'Power affects these relations. Epistemic injustice occurs when prejudice unfairly reduces a speaker’s credibility or when shared interpretive resources make an experience difficult to understand and communicate. Misinformation and algorithmic media add further problems: repetition can mimic corroboration, visibility can be mistaken for reliability, and institutional incentives can reward confidence over correction.'
    ],['political-philosophy','ethics'],[],['Epistemic Injustice']),
    section('reading','How to enter epistemology',[
      'Begin with a concrete problem rather than a definition list. Plato’s Theaetetus shows why defining knowledge is difficult. Descartes’ first two Meditations let the reader perform foundational doubt. Hume’s discussion of induction demonstrates how an apparently abstract problem sits beneath ordinary prediction and science. Gettier then reveals why a plausible modern analysis fails.',
      'From there, compare theories of justification and move into social epistemology. Ask of each theory what cases it explains, what kind of knower it assumes, and whether it can address institutions as well as individuals. Epistemology is most useful when it improves inquiry without pretending that every responsible belief can be converted into certainty.'
    ],['epistemology'],['plato','descartes','hume','kant'],['Theaetetus','Meditations on First Philosophy','Enquiry Concerning Human Understanding'])
  ],
  ethics:[
    section('overview','Reasons for action and forms of life',[
      'Ethics asks what people have reason to do, what kind of persons they should become, and what institutions or relationships allow lives to go well. It is broader than a code of permitted and forbidden actions. Ethical judgment involves character, consequences, principles, emotion, attention, dependency, and the social conditions under which choices become possible.',
      'The major approaches should not be treated as three slogans competing to solve every case. Virtue ethics asks how practical judgment and character are formed. Deontology asks what respect and obligation require independently of advantage. Consequentialism asks whether decisions adequately consider their effects on everyone affected. Care ethics and feminist ethics reveal forms of dependency and power obscured by theories centered on independent, interchangeable agents.'
    ],['virtue-ethics','deontology','utilitarianism'],['aristotle','kant','mill'],['Nicomachean Ethics','Groundwork of the Metaphysics of Morals','Utilitarianism']),
    section('ancient','Flourishing, virtue, and practice',[
      'Ancient Greek ethics commonly begins from the question of flourishing across a complete life. Aristotle argues that flourishing is activity in accordance with virtue, supported by relationships, institutions, and enough external goods to act well. Virtue is not a feeling or isolated heroic act. It is a stable disposition formed through habituation and guided by practical wisdom, the capacity to perceive what matters in a particular situation.',
      'Hellenistic schools make philosophy a disciplined way of life under unstable political conditions. Stoics locate unconditional good in virtue and train judgment, desire, and action. Epicureans analyze desires and fears to secure tranquil pleasure and friendship. These traditions disagree sharply, but all reject the idea that ethics can be mastered by memorizing propositions without transforming habits and attention.'
    ],['virtue-ethics','stoicism','epicureanism'],['aristotle','epicurus','epictetus'],['Nicomachean Ethics','Discourses']),
    section('modern','Duty, sentiment, and consequences',[
      'Modern moral philosophy intensifies disagreements about the source of obligation. Hume argues that reason alone does not motivate and develops an ethics grounded in sentiment, sympathy, and social usefulness. Kant grounds morality in autonomy: a rational agent should act only on principles that can be willed universally and must treat persons as ends rather than mere means.',
      'Utilitarianism evaluates actions and institutions by their consequences for well-being. Mill defends the approach while distinguishing qualities of pleasure and protecting individuality as a major component of human flourishing. These theories reveal different moral dangers. A focus on duty can become rigid or abstract; a focus on consequences can permit unacceptable sacrifice; a focus on sentiment can reproduce partiality and prejudice.'
    ],['deontology','utilitarianism'],['hume','kant','mill'],['Groundwork of the Metaphysics of Morals','Utilitarianism']),
    section('care-power','Care, power, and moral psychology',[
      'Care ethics begins from dependency and relationship rather than imagining agents as fully independent choosers. Children, ill people, older people, and everyone at different stages rely on practices of care. Ethical theory must therefore ask who performs that labor, how it is valued, and whether responsiveness can coexist with justice rather than becoming an excuse for exploitation.',
      'Feminist, critical, and genealogical approaches also ask how moral vocabularies are shaped by power. Nietzsche investigates the histories and psychological functions of moral values. Beauvoir analyzes how unequal situations constrain freedom and why willing one’s own freedom requires willing freedom for others. Moral psychology studies how emotion, habit, identity, self-deception, and social expectation affect the capacity to act on reasons.'
    ],['feminist-philosophy','continental-philosophy'],['nietzsche','beauvoir'],['On the Genealogy of Morality','The Ethics of Ambiguity']),
    section('metaethics','What kind of truth is a moral truth?',[
      'Metaethics asks what moral judgments mean and what could make them true. Realists argue that at least some moral claims are objectively true. Constructivists ground moral authority in procedures or standpoints of practical reasoning. Expressivists emphasize how moral language voices commitments and guides action. Error theorists argue that ordinary moral claims purport to state objective facts but systematically fail.',
      'These positions affect how disagreement is understood. If moral truth is objective, why is disagreement persistent and culturally patterned? If values are constructed, what prevents oppressive constructions from legitimating themselves? If moral judgments express attitudes, how can reasoning improve them? Metaethics does not replace practical ethics, but it clarifies what people assume when they argue that an action is wrong rather than merely disliked.'
    ],['ethics','epistemology'],[],[]),
    section('reading','Learning to compare ethical arguments',[
      'A productive route begins with Aristotle on flourishing and habituation, Kant on duty and respect, and Mill on welfare and liberty. Read each as identifying a moral phenomenon the others risk overlooking. Then add care ethics, moral psychology, and a concrete applied problem. The purpose is not to select a team after three excerpts, but to understand which questions each framework makes visible.',
      'When assessing an ethical argument, ask what it treats as morally basic, how it handles conflict, whose perspective it assumes, and what institutions its recommendations require. Good ethical reasoning moves between principles and cases while remaining alert to uncertainty, power, and the possibility that a familiar description of the problem is already morally loaded.'
    ],['ethics','virtue-ethics','deontology','utilitarianism'],['aristotle','kant','mill'],['Nicomachean Ethics','Groundwork of the Metaphysics of Morals','Utilitarianism'])
  ],
  'analytic-philosophy':[
    section('overview','A tradition of methods, not one doctrine',[
      'Analytic philosophy is a broad and internally contested tradition associated with careful argument, explicit distinctions, logic, and attention to language. It does not possess one subject matter or political outlook. Analytic philosophers work on metaphysics, ethics, mind, language, science, mathematics, law, race, gender, and many other areas. What unifies the tradition, if anything, is a changing set of methods and exemplary problems rather than a creed.',
      'The label can mislead when it is treated as the simple opposite of “continental philosophy.” The traditions have overlapping sources and topics, and each contains many styles. Analytic philosophy is best understood historically: it begins with transformations in logic and reactions against idealism, changes through logical positivism and ordinary-language philosophy, and becomes increasingly plural after mid-century critiques of its own assumptions.'
    ],['logic','philosophy-of-language'],['frege','russell','wittgenstein'],['On Sense and Reference','On Denoting']),
    section('origins','Frege, Russell, and logical analysis',[
      'Frege developed a new logical language powerful enough to represent complex patterns of quantification and inference. His distinction between sense and reference explains how two expressions can refer to the same object while presenting it differently, making an identity statement informative. These innovations transformed logic, philosophy of mathematics, and the study of meaning.',
      'Russell used logical analysis to reveal structures concealed by ordinary grammar. His theory of descriptions analyzes a sentence containing “the present king of France” without treating the phrase as a name that must refer to an object. Analysis promised to dissolve philosophical puzzles by replacing misleading surface form with clearer logical form. Moore’s defense of common sense and attention to conceptual distinctions offered a different but related reaction against grand idealist systems.'
    ],['logic','philosophy-of-language','analytic-philosophy'],['frege','russell','g-e-moore'],['On Sense and Reference','On Denoting']),
    section('positivism','Early Wittgenstein and logical positivism',[
      'The Tractatus proposes that meaningful propositions picture possible facts through shared logical form. The Vienna Circle drew from this work, empiricism, and modern science to challenge metaphysics and clarify scientific language. Verificationist proposals tied cognitive meaning to empirical confirmation or logical truth, promising a sharp boundary between meaningful inquiry and pseudo-problems.',
      'The program proved too restrictive and faced problems explaining its own verification principle, theoretical scientific language, ethics, and ordinary discourse. Still, logical positivism permanently changed philosophy of science and standards of argumentative clarity. Its failure also illustrates an analytic strength: central movements are often transformed by criticism arising from inside their own methods.'
    ],['philosophy-of-science','logic'],['wittgenstein','carnap'],['Tractatus Logico-Philosophicus']),
    section('ordinary-language','Use, practice, and ordinary language',[
      'Later Wittgenstein rejects the demand that all meaningful language share one logical essence. Words work within language-games embedded in human practices. Philosophical problems often arise when expressions are removed from those settings and forced into an oversimplified picture. Ordinary-language philosophers such as Austin and Ryle similarly examine what people do with words and how conceptual distinctions function.',
      'This turn does not imply that ordinary usage is infallible or that philosophy should become dictionary work. The point is that theories must answer to the complex practices they claim to explain. Analyses of promising, knowing, intending, perceiving, or acting can fail when they ignore differences already visible in competent use.'
    ],['philosophy-of-language','philosophy-of-mind'],['wittgenstein','anscombe'],['Philosophical Investigations','Intention']),
    section('quine-after','Quine and the plural contemporary field',[
      'Quine challenged two assumptions associated with earlier analytic philosophy: a sharp distinction between truths based on meaning and truths based on fact, and the hope that each meaningful statement could be reduced to immediate experience. He instead described beliefs as facing experience in interconnected networks and argued for philosophy’s continuity with empirical science.',
      'After Quine, analytic philosophy did not move in one direction. Metaphysics revived; philosophy of mind engaged cognitive science; ethics and political philosophy developed sophisticated normative theories; language and logic remained central while experimental and formal methods expanded. Contemporary work also confronts social identity, structural injustice, and nonideal conditions, challenging older pictures of a detached universal speaker.'
    ],['epistemology','philosophy-of-science','metaphysics'],['quine','rawls'],['Two Dogmas of Empiricism']),
    section('debates-reading','Internal debates and how to read the tradition',[
      'Analytic philosophy continually debates its own method. Conceptual analysts ask what can be learned through reflection on cases and language; naturalists argue that philosophy should be continuous with science; formal philosophers build mathematical models; ordinary-language and therapeutic approaches question the urge to theorize. Disagreements over intuitions, expertise, history, and social standpoint reveal that clarity is an achievement requiring criticism, not a neutral possession.',
      'A useful reading path moves historically. Read Frege or Russell to see why logical analysis seemed revolutionary, early and later Wittgenstein to witness a major internal transformation, and Quine to understand the breakdown of earlier boundaries. Then compare contemporary work in a substantive field such as mind, ethics, or science. This prevents “analytic” from becoming a vague synonym for short arguments and recognizes it as a changing conversation about what philosophical rigor requires.'
    ],['analytic-philosophy','logic','philosophy-of-language'],['frege','russell','wittgenstein','quine'],['On Denoting','Tractatus Logico-Philosophicus','Philosophical Investigations','Two Dogmas of Empiricism'])
  ]
};
